redirect_uri = 'http://localhost:5000/callback'

def validate_redirect_uri(redirect_uri):
    domain = 'example.com'  # Replace with your domain
    if domain not in redirect_uri:
        return False
    return True

@app.route('/login')
def login():
    if not validate_redirect_uri(redirect_uri):
        return 'Invalid redirect URI', 400
    
    auth_url, state = authorization_base_url + '?response_type=code&client_id=' + client_id + '&redirect_uri=' + redirect_uri + '&scope=read'
    
    # Store the state in session for CSRF protection
    session['state'] = state
    
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    if not code:
        return 'Authorization failed', 401
    
    token_url += '?grant_type=authorization_code&code=' + code + '&redirect_uri=' + redirect_uri
    headers = {'Content-Type': 'application/x-www-form-urlencoded'}
    data = {'client_id': client_id, 'client_secret': client_secret}
    
